  : [{ type: 'text', text: caption || 'El cliente envió un archivo. Acusa recibo amablemente.' }];

try {
  const resp = await fetch('https://api.openai.com/v1/chat/completions', {
    method: 'POST',
    headers: {
      'Authorization': 'Bearer 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',
      'Content-Type': 'application/json'
