// Save conversation exchange to n8n workflow static data
const staticData = $getWorkflowStaticData('global');
const phone = items[0].json.phone;
const userMsg = items[0].json.userMessage || '';
const aiResp = items[0].json.cleanResponse || items[0].json.aiResponse || '';

if (!staticData[phone]) staticData[phone] = [];

// Add user + assistant messages
if (userMsg) staticData[phone].push({ role: 'user', content: userMsg });
if (aiResp) staticData[phone].push({ role: 'assistant', content: aiResp.replace('[SOLICITA_LLAMADA]','').trim() });

// Keep only last 30 messages per phone (15 exchanges)
if (staticData[phone].length > 30) {
  staticData[phone] = staticData[phone].slice(-30);
}

return items;

// Find the conversation for this phone number — strict matching
const phone = $('Extraer respuesta AI').item.json.phone;
const allConvs = items[0].json.data?.payload || [];

const normalize = (p) => (p || '').replace(/\D/g, '').replace(/^1/, '').slice(-10);
const normalizedPhone = normalize(phone);

const myConv = allConvs.find(c => {
  const sender = c.meta?.sender?.phone_number || '';
  return normalize(sender) === normalizedPhone;
});

return [{json: {
  convId: myConv?.id || null,
  phone: phone,
  pushName: $('Extraer respuesta AI').item.json.pushName,
  cleanResponse: $('Extraer respuesta AI').item.json.cleanResponse
}}];

const staticData = $getWorkflowStaticData('global');
if (!staticData.pausedContacts) staticData.pausedContacts = {};

const action = $json.cmdAction;
const senderPhone = $json.phone;
const cmdPhone = $json.cmdPhone;
const targetPhone = (cmdPhone && cmdPhone.length > 4) ? cmdPhone : senderPhone;

let msg = '';
let ghlAction = null;

if (action === 'STOP') {
  staticData.pausedContacts[targetPhone] = true;
  ghlAction = 'pause';
  msg = targetPhone === senderPhone
    ? '⏸️ Entendido, no te escribiré más. Si en el futuro necesitas ayuda, escríbeme CONTINUE.'
    : '⏸️ Pausado. Lucy no responderá a +' + targetPhone + '. Envía CONTINUE ' + targetPhone + ' para reanudar.';
} else {
  delete staticData.pausedContacts[targetPhone];
  ghlAction = 'resume';
  msg = targetPhone === senderPhone
    ? '▶️ ¡Con gusto! Aquí estoy para ayudarte. ¿En qué te puedo asistir?'
    : '▶️ Reanudado. Lucy retomará la conversación con +' + targetPhone + '.';
}

try {
  const searchResp = await fetch('https://services.leadconnectorhq.com/contacts/?locationId=IYslAlpLthyYmzorDhnP&query=' + encodeURIComponent('+' + targetPhone), {
    method: 'GET',
    headers: {
      'Authorization': 'Bearer pit-b467b97c-de3a-4321-bb0f-e9f09c380faf',
      'Version': '2021-07-28'
    }
  });
  const searchData = await searchResp.json();
  const contacts = searchData.contacts || [];
  if (contacts.length > 0) {
    const contactId = contacts[0].id;
    const currentTags = contacts[0].tags || [];
    const newTags = ghlAction === 'pause'
      ? [...new Set([...currentTags, 'lucy-paused'])]
      : currentTags.filter(t => t !== 'lucy-paused');
    await fetch('https://services.leadconnectorhq.com/contacts/' + contactId, {
      method: 'PUT',
      headers: {
        'Authorization': 'Bearer pit-b467b97c-de3a-4321-bb0f-e9f09c380faf',
        'Version': '2021-07-28',
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ tags: newTags })
    });
  }
} catch(e) { /* GHL tag update is best-effort */ }

return [{ json: { confirmMsg: msg, senderPhone: senderPhone, targetPhone: targetPhone } }];

const staticData = $getWorkflowStaticData('global');
const paused = staticData.pausedContacts || {};
const phone = $json.phone;
const isPaused = !!paused[phone];
return [{ json: { ...$json, isPaused } }];

const staticData = $getWorkflowStaticData('global');
const msgId = $input.first().json?.body?.data?.key?.id;
const phone = $input.first().json?.body?.data?.key?.remoteJid?.split('@')[0] || '';
if (!msgId) return $input.all();

if (!staticData.processedIds) staticData.processedIds = {};
if (!staticData.rateLimits) staticData.rateLimits = {};

// Rate limiting: max 10 messages per 60 seconds per phone
const now = Date.now();
const minute = 60000;
if (phone) {
  if (!staticData.rateLimits[phone]) staticData.rateLimits[phone] = [];
  staticData.rateLimits[phone] = staticData.rateLimits[phone].filter(t => now - t < minute);
  if (staticData.rateLimits[phone].length >= 10) {
    return []; // Rate limited — silently drop
  }
  staticData.rateLimits[phone].push(now);
  // Cleanup: keep only 300 phones in rate limit table
  const rlKeys = Object.keys(staticData.rateLimits);
  if (rlKeys.length > 300) rlKeys.slice(0, rlKeys.length - 300).forEach(k => delete staticData.rateLimits[k]);
}

// Dedup: trim to last 500 IDs
const keys = Object.keys(staticData.processedIds);
if (keys.length > 500) {
  keys.slice(0, keys.length - 500).forEach(k => delete staticData.processedIds[k]);
}

if (staticData.processedIds[msgId]) {
  return [];
}
staticData.processedIds[msgId] = Date.now();
return $input.all();

const staticData = $getWorkflowStaticData('global');
if (!staticData.lastResponseFor) staticData.lastResponseFor = {};

const phone = items[0].json.phone || '';
const msgId = items[0].json.messageId || '';

// Output-level dedup: if same messageId already generated a response, skip
if (msgId && phone && staticData.lastResponseFor[phone] === msgId) {
  return []; // Duplicate — already responded to this message
}
if (msgId && phone) {
  staticData.lastResponseFor[phone] = msgId;
  const lrKeys = Object.keys(staticData.lastResponseFor);
  if (lrKeys.length > 300) lrKeys.slice(0, lrKeys.length - 300).forEach(k => delete staticData.lastResponseFor[k]);
}

// Random 2-4 sec delay to simulate human typing
const ms = Math.floor(Math.random() * 2000) + 2000;
await new Promise(r => setTimeout(r, ms));
return $input.all();

const ai = $('Extraer respuesta AI').item.json;
const clientPhone = ai.phone || '';
const clientName  = ai.pushName || 'Cliente';
const motivo      = (ai.motivoLlamada || 'consulta de seguros').slice(0, 100);

const twimlUrl =
  `https://n8n-n8n.78s07r.easypanel.host/webhook/lucy-twiml` +
  `?clientPhone=${encodeURIComponent(clientPhone)}` +
  `&clientName=${encodeURIComponent(clientName)}` +
  `&topic=${encodeURIComponent(motivo)}`;

const qs = (o) => Object.entries(o).map(([k,v]) => `${encodeURIComponent(k)}=${encodeURIComponent(v)}`).join('&');

try {
  const resp = await fetch('https://api.twilio.com/2010-04-01/Accounts/TU_TWILIO_ACCOUNT_SID/Calls', {
    method: 'POST',
    headers: {
      'Authorization': 'Basic TU_TWILIO_AUTH_TOKEN_BASE64',
      'Content-Type': 'application/x-www-form-urlencoded'
    },
    body: qs({ To: '+16155467023', From: '+14079555784', Url: twimlUrl })
  });
  const data = await resp.json();
  const sid = data?.sid || '';
  return [{ json: { twilioQueued: true, callSid: sid, to: '+16155467023', clientPhone } }];
} catch(e) {
  return [{ json: { twilioError: e.message, clientPhone } }];
}

const staticData = $getWorkflowStaticData('global');
const phone = $('Extraer datos').item.json.phone;
const caption = $('Extraer datos').item.json.mediaCaption || '[imagen/documento]';
const aiResp = $('OpenAI Vision').item.json.visionResponse || '';

if (phone) {
  if (!staticData[phone]) staticData[phone] = [];
  staticData[phone].push({ role: 'user', content: caption });
  if (aiResp) staticData[phone].push({ role: 'assistant', content: aiResp });
  if (staticData[phone].length > 30) staticData[phone] = staticData[phone].slice(-30);
}
return $input.all();

const staticData = $getWorkflowStaticData('global');
if (!staticData.pausedContacts) staticData.pausedContacts = {};
const phone = $('Extraer respuesta AI').item.json.phone;
if (phone) {
  staticData.pausedContacts[phone] = true;
  try {
    const searchResp = await fetch('https://services.leadconnectorhq.com/contacts/?locationId=IYslAlpLthyYmzorDhnP&query=' + encodeURIComponent('+' + phone), {
      method: 'GET',
      headers: { 'Authorization': 'Bearer pit-b467b97c-de3a-4321-bb0f-e9f09c380faf', 'Version': '2021-07-28' }
    });
    const searchData = await searchResp.json();
    const contacts = searchData.contacts || [];
    if (contacts.length > 0) {
      const contactId = contacts[0].id;
      const newTags = [...new Set([...(contacts[0].tags || []), 'lucy-paused'])];
      await fetch('https://services.leadconnectorhq.com/contacts/' + contactId, {
        method: 'PUT',
        headers: { 'Authorization': 'Bearer pit-b467b97c-de3a-4321-bb0f-e9f09c380faf', 'Version': '2021-07-28', 'Content-Type': 'application/json' },
        body: JSON.stringify({ tags: newTags })
      });
    }
  } catch(e) { /* best-effort */ }
}
return $input.all();

// Merge Evolution API base64 response with original message data
const apiResp = $input.first().json;
const orig = $('Extraer datos').item.json;

const base64 = apiResp.base64 || '';
const isAudio = orig.messageType === 'audioMessage' || orig.messageType === 'pttMessage';
const defaultMimetype = isAudio ? 'audio/ogg; codecs=opus' : 'image/jpeg';
const mimetype = apiResp.mimetype || defaultMimetype;

return [{ json: {
  ...orig,
  base64,
  mimetype,
  mediaError: base64 ? undefined : 'base64_empty_api'
}}];

const item = $input.first().json;
const base64Clean = (item.base64 || '').replace(/^data:[^;]+;base64,/, '');
const mimetype = item.mimetype || 'audio/ogg; codecs=opus';
let ext = 'ogg';
if (mimetype.includes('mp4')) ext = 'mp4';
else if (mimetype.includes('mp3') || mimetype.includes('mpeg')) ext = 'mp3';
else if (mimetype.includes('webm')) ext = 'webm';
else if (mimetype.includes('wav')) ext = 'wav';
else if (mimetype.includes('m4a')) ext = 'm4a';

return [{
  json: {
    phone: item.phone,
    remoteJid: item.remoteJid,
    pushName: item.pushName,
    messageId: item.messageId
  },
  binary: {
    audioFile: {
      data: base64Clean,
      mimeType: mimetype,
      fileName: 'audio.' + ext
    }
  }
}];

const resp = $input.first().json;
const meta = $('Prep Audio Binary').item.json;
const transcription = resp.text || '';
return [{
  json: {
    phone: meta.phone,
    remoteJid: meta.remoteJid,
    pushName: meta.pushName,
    messageId: meta.messageId,
    message: transcription || '[audio no procesado]',
    transcription: transcription,
    messageType: 'text',
    hasMedia: false
  }
}];

const phone = $('Extraer datos').item.json.phone;
const pushName = $('Extraer datos').item.json.pushName || 'Cliente';
const reservarInfo = $('Extraer respuesta AI').item.json.reservarInfo || '';
const reagendarInfo = $('Extraer respuesta AI').item.json.reagendarInfo || '';
const cancelarRequested = $('Extraer respuesta AI').item.json.cancelarRequested || false;
const EVO_HOST = 'n8n-evolution-api.78s07r.easypanel.host';
const EVO_INSTANCE = 'Dayana%20Munoz';
const evoUrl = 'https://' + EVO_HOST + '/message/sendText/' + EVO_INSTANCE;
const base = { phone, pushName, evoUrl, ghlLocationId: 'IYslAlpLthyYmzorDhnP', ghlCalendarId: 'xyMoZ5iLareyhwQNijO5', royPhone: '16155467023' };

// CANCELAR
if (cancelarRequested) return [{ json: { ...base, action: 'cancelar' } }];

// Helper: parse date
const parseDateTime = (info) => {
  if (!info || !info.includes('T')) return null;
  const [datePart, timePart] = info.split('T');
  const [year, month, day] = datePart.split('-').map(Number);
  const [hour, minute] = (timePart || '09:00').split(':').map(Number);
  const startUTC = new Date(Date.UTC(year, month-1, day, hour+4, minute));
  const endUTC = new Date(startUTC.getTime() + 3600000);
  const MONTHS = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
  const DAYS = ['domingo','lunes','martes','miercoles','jueves','viernes','sabado'];
  const dateObj = new Date(Date.UTC(year, month-1, day));
  const ampm = hour < 12 ? 'AM' : 'PM';
  const h12 = hour%12||12;
  const dateStr = DAYS[dateObj.getUTCDay()]+' '+day+' de '+MONTHS[month-1]+' a las '+h12+':'+String(minute).padStart(2,'0')+' '+ampm+' ET';
  return { startTime: startUTC.toISOString(), endTime: endUTC.toISOString(), dateStr };
};

// REAGENDAR
if (reagendarInfo) {
  const parsed = parseDateTime(reagendarInfo);
  if (parsed) return [{ json: { ...base, action: 'reagendar', ...parsed, apptTitle: 'Cita reagendada - '+pushName } }];
}

// NUEVA CITA / LINK
if (!reservarInfo || !reservarInfo.includes('T')) {
  return [{ json: { ...base, action: 'link', ghlCalendarId: 'xyMoZ5iLareyhwQNijO5' } }];
}

const parsed = parseDateTime(reservarInfo);
if (!parsed) return [{ json: { ...base, action: 'link' } }];
return [{ json: { ...base, action: 'cita', ...parsed, apptTitle: 'Cita con '+pushName } }];

const ghlResp = $input.first().json;
const p = $('Parsear cita').item.json;
const contact = ghlResp.contacts && ghlResp.contacts[0];
const contactId = contact ? contact.id : '';

return [{ json: {
  contactId,
  phone: p.phone, pushName: p.pushName, dateStr: p.dateStr,
  startTime: p.startTime, endTime: p.endTime,
  ghlLocationId: p.ghlLocationId, ghlCalendarId: p.ghlCalendarId,
  apptTitle: p.apptTitle, evoUrl: p.evoUrl, royPhone: p.royPhone
}}];

const body = $input.first().json?.body || {};
const fromMe = body?.data?.key?.fromMe === true;
const event = body?.event === 'messages.upsert';
const remoteJid = body?.data?.key?.remoteJid || '';
const isGroup = remoteJid.includes('@g.us');
const msg = (body?.data?.message?.conversation || body?.data?.message?.extendedTextMessage?.text || '').toLowerCase().trim();

const commandWords = ['stop','continue','continuar','reanudar','no me escribas','no me molestes','unsubscribe','borrame','no quiero mensajes','no me contactes','no me llames','borra mi numero','no mas mensajes'];
const hasCommand = commandWords.some(w => msg.includes(w));

if (fromMe && event && !isGroup && hasCommand) {
  return $input.all();
}
return [];

const item = $input.first().json;
const docRequested = $('Extraer respuesta AI').item.json.docRequested;
const docName = ($('Extraer respuesta AI').item.json.docName || '').toLowerCase().trim();
const phone = $('Extraer datos').item.json.phone;

if (!docRequested || !docName || !phone) return [{ json: { docSent: false, reason: 'not_requested' } }];

