const EVO_INSTANCE = 'Dayana%20Munoz';
const EVO_KEY = '429683C4C977415CAAFCCE10F7D57E11';

const docs = {
  'seguro_vida':      { url: 'PENDIENTE', name: 'Seguro-de-Vida-DayanaFinance.pdf' },
  'cancer':           { url: 'PENDIENTE', name: 'Poliza-Cancer-DayanaFinance.pdf' },
  'dental':           { url: 'PENDIENTE', name: 'Plan-Dental-DayanaFinance.pdf' },
  'hospital':         { url: 'PENDIENTE', name: 'Hospital-Indemnity-DayanaFinance.pdf' },
  'accidente':        { url: 'PENDIENTE', name: 'Poliza-Accidente-DayanaFinance.pdf' },
