const phone = $('Extraer datos').item.json.phone;
const message = $('Extraer datos').item.json.message || '[media]';
const pushName = $('Extraer datos').item.json.pushName || 'Cliente';
const GHL_KEY = 'pit-b467b97c-de3a-4321-bb0f-e9f09c380faf';
const GHL_LOC = 'IYslAlpLthyYmzorDhnP';
const H = { 'Authorization': `Bearer ${GHL_KEY}`, 'Version': '2021-07-28', 'Content-Type': 'application/json' };

// Get contactId from GHL Crear Contacto response
const ghlResp = $('GHL Crear Contacto').item.json;
let contactId = ghlResp?.contact?.id || ghlResp?.id || '';

// If no contactId, search by phone
if (!contactId) {
  try {
    const s = await fetch(`https://services.leadconnectorhq.com/contacts/search?query=${encodeURIComponent('+'+phone)}&locationId=${GHL_LOC}`, { method:'GET', headers:H });
    const d = await s.json();
    contactId = d?.contacts?.[0]?.id || '';
  } catch(e) {}
}
if (!contactId) return [{ json: { synced: false, reason: 'no_contact_id' } }];

// Find or create conversation
let convId = null;
try {
  const cs = await fetch(`https://services.leadconnectorhq.com/conversations/search?locationId=${GHL_LOC}&contactId=${contactId}`, { method:'GET', headers:H });
  const cd = await cs.json();
  convId = cd?.conversations?.[0]?.id || null;
} catch(e) {}

if (!convId) {
  try {
    const cc = await fetch('https://services.leadconnectorhq.com/conversations/', {
      method:'POST', headers:H,
      body: JSON.stringify({ locationId: GHL_LOC, contactId })
    });
    const ccd = await cc.json();
    convId = ccd?.conversation?.id || ccd?.id || null;
  } catch(e) {}
}
if (!convId) return [{ json: { synced: false, reason: 'no_conv_id' } }];

// Save convId for later use by AI response logger
const sd = $getWorkflowStaticData('global');
if (!sd.ghlConvIds) sd.ghlConvIds = {};
