// Log inbound message
try {
  await fetch(`https://services.leadconnectorhq.com/conversations/${convId}/messages`, {
    method:'POST', headers:H,
    body: JSON.stringify({ type: 1, message, html: `<p>${message}</p>`, contactId, direction: 'inbound', attachments: [] })
  });
} catch(e) {}

return [{ json: { synced: true, convId, contactId, phone } }];

const phone = $('Extraer datos').item.json.phone;
const aiResponse = $('Extraer respuesta AI').item.json.cleanResponse || '';
if (!aiResponse || !phone) return [{ json: { logged: false } }];

const GHL_KEY = 'pit-b467b97c-de3a-4321-bb0f-e9f09c380faf';
const H = { 'Authorization': `Bearer ${GHL_KEY}`, 'Version': '2021-07-28', 'Content-Type': 'application/json' };

const sd = $getWorkflowStaticData('global');
const convId = sd?.ghlConvIds?.[phone];
if (!convId) return [{ json: { logged: false, reason: 'no_conv_id' } }];

try {
  await fetch(`https://services.leadconnectorhq.com/conversations/${convId}/messages`, {
    method:'POST', headers:H,
    body: JSON.stringify({ type: 1, message: `[Andrea IA] ${aiResponse}`, html: `<p>[Andrea IA] ${aiResponse}</p>`, direction: 'outbound', attachments: [] })
  });
  return [{ json: { logged: true, convId, phone } }];
} catch(e) {
  return [{ json: { logged: false, error: e.message } }];
}

const appts = $input.first().json.appointments || $input.first().json.items || [];
const parsedCita = $('Parsear cita').item.json;
